INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(85, 29, 1, 'comprehension',
'According to the passage, what has been one of the most notable achievements of fecal microbiota transplantation?',
'第3段落で、FMTが「再発性クロストリディオイデス・ディフィシル感染症に対して著しく効果的な治療法として台頭し、90パーセントを超える治癒率を達成」し、「従来の抗生物質療法の効力をはるかに凌ぐ」と述べている。選択肢2が「再発性C. difficile感染症に対して従来の抗生物質より優れた治癒率を達成」と正確に反映。選択肢1は「自閉症スペクトラム障害の治療に効果」で本文はFMTについてそこまで述べていない。選択肢3は「すべての腸疾患に有効」で本文より広すぎる。選択肢4は「副作用がない」で本文に言及なし。',
2),
(86, 29, 2, 'comprehension',
'What concern do skeptics raise about the commercialization of microbiome research?',
'第4段落末で、「厳密な臨床的証拠に裏づけられていない誇大な健康効果を主張するプロバイオティクスサプリメントの商業的急増は、マイクロバイオーム科学が提供できるものとできないものについての公衆の理解を曇らせている」と述べている。選択肢4が「科学的裏づけのない健康効果の主張が公衆の理解を歪めている」と正確に対応。選択肢1は「研究資金が不足」で本文の論点と異なる。選択肢2は「個人データの悪用」で本文に言及なし。選択肢3は「治療法が高額」で本文の該当部分の懸念とは異なる。',
4),
(87, 29, 3, 'fill_in_blank',
'Choose the best option to fill in the blank [BLANK] in the passage.',
'空所は「予備的な臨床試験は[BLANK]をもたらしている」という文脈で、直後に「しかしこの分野の軌道はマイクロバイオームに基づく治療法がますます重要な位置を占めることを示唆している」と逆接で続く。まだ発展途上で結果が出揃っていないが将来性はあるという文脈。選択肢3「有望だが一貫しない結果」が最も適切。選択肢1「決定的に否定的な結果」は「将来性がある」という後続の文と矛盾。選択肢2「圧倒的に肯定的な結果」は逆接の「but」と整合しない。選択肢4「統計的に有意でない結果」も将来性への言及と矛盾。',
3);

